module Gray_code_counter(
   input                clk,
   input                rst_n,

   output reg [3:0]     Q
);
    reg [3:0] gray_counter;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            gray_counter <= 4'b0000;
            Q <= 4'b0000;
        end
        else begin
            gray_counter <= gray_counter + 1;
            Q <= gray_counter ^ (gray_counter >> 1);
        end
    end
endmodule
